    // Lista que guarda todas las tablas de simbolos para imprimir al final
    static java.util.ArrayList<AmbitoInfo> todasLasTablas = new java.util.ArrayList<>();
    
    // Guarda la info de un ambito (nombre, tabla y nivel de anidamiento)
    static class AmbitoInfo {
        String nombre;
        java.util.HashMap<String, Simbolo> tabla;
        int nivel;
        
        AmbitoInfo(String nombre, java.util.HashMap<String, Simbolo> tabla, int nivel) {
            this.nombre = nombre;
            this.tabla = tabla;
            this.nivel = nivel;
        }
    }

    // ===============================================================
    // 2.1.5 MANEJO DE AMBITOS
    // ===============================================================

    // Agrega un nuevo ambito a la pila
    public static void pushScope(String nombre) {
        pilaTablas.push(new java.util.HashMap<>());
        nombresAmbitos.push(nombre);
    }
    
    // Elimina el ambito actual y lo guarda para imprimir despues
    public static void popScope() {
        if (!pilaTablas.isEmpty()) {
            java.util.HashMap<String, Simbolo> ambito = pilaTablas.pop();
            String nombre = nombresAmbitos.pop();
            int nivel = nombresAmbitos.size();
            
            todasLasTablas.add(new AmbitoInfo(nombre, ambito, nivel));
        }
    }

    // Imprime todas las tablas de simbolos al final del analisis
    public static void imprimirTodasLasTablas() {
        for (int i = todasLasTablas.size() - 1; i >= 0; i--) {
            AmbitoInfo a = todasLasTablas.get(i);
            
            String indentacion = "";
            for (int j = 0; j < a.nivel; j++) {
                indentacion += "               ";
            }
            
            System.out.println("\n" + indentacion + "=== TABLA DE SIMBOLOS: " + a.nombre + " ===");
            imprimirTabla(a.tabla, indentacion + "  ");
        }
        todasLasTablas.clear();
    }

    // ===============================================================
    // 2.1.6 OPERACIONES CON SIMBOLOS
    // ===============================================================

    // Registra una nueva variable en la tabla del ambito actual
    public static void agregarSimbolo(String nombre, String tipo, int linea, boolean inicializada) {
        if (pilaTablas.isEmpty()) return;
        java.util.HashMap<String, Simbolo> ambito = pilaTablas.peek();
        if (ambito.containsKey(nombre)) {
            errorSemantico("Linea " + linea + ": variable '" + nombre + "' ya fue declarada en este ambito.");
        } else {
            ambito.put(nombre, new Simbolo(nombre, tipo, linea, "variable", inicializada));
        }
    }

    // Registra un parametro en la tabla del ambito actual
    public static void agregarParametro(String nombre, String tipo, int linea) {
        if (pilaTablas.isEmpty()) return;
        java.util.HashMap<String, Simbolo> ambito = pilaTablas.peek();
        if (ambito.containsKey(nombre)) {
            errorSemantico("Linea " + linea + ": parametro '" + nombre + "' ya fue declarado en este ambito.");
        } else {
            ambito.put(nombre, new Simbolo(nombre, tipo, linea, "parametro", true)); // true: los parametros ya vienen inicializados
        }
    }

    // Muestra el contenido de una tabla de simbolos
    private static void imprimirTabla(java.util.HashMap<String, Simbolo> tabla, String indentacion) {
        if (tabla.isEmpty()) {
            System.out.println(indentacion + "(sin variables)");
            return;
        }
        System.out.println(indentacion + String.format("%-20s %-10s %-12s %s", "Variable", "Tipo", "Categoria", "Linea"));
        System.out.println(indentacion + String.format("%-20s %-10s %-12s %s", "--------", "----", "---------", "-----"));
        for (java.util.Map.Entry<String, Simbolo> e : tabla.entrySet()) {
            Simbolo s = e.getValue();
            System.out.println(indentacion + String.format("%-20s %-10s %-12s %s", s.nombre, s.tipo, s.categoria, s.linea));
        }
    }
    
    // Actualiza el tipo de un simbolo existente (para arreglos)
    public static void actualizarTipoSimbolo(String nombre, String nuevoTipo) {
        for (java.util.HashMap<String, Simbolo> ambito : pilaTablas) {
            if (ambito.containsKey(nombre)) {
                ambito.get(nombre).tipo = nuevoTipo;
                return;
            }
        }
    }

    // ===============================================================
    // 2.1.7 MANEJADORES DE ERRORES SINTACTICOS
    // ===============================================================

    // Error sintactico: token inesperado
    public void syntax_error(java_cup.runtime.Symbol s) {
        erroresSintacticos++;
        System.err.println(ANSI_BLUE + "[ERROR SINTACTICO] Linea " + s.left + ", columna " + s.right
                + ": token inesperado -> '" + s.value + "'" + ANSI_RESET);
    }

    // Error sintactico irrecuperable
    public void unrecovered_syntax_error(java_cup.runtime.Symbol s) {
        erroresSintacticos++;
        System.err.println(ANSI_BLUE_DARK + "[ERROR SINTACTICO IRRECUPERABLE] Linea " + s.left
                + ": no se pudo continuar el analisis." + ANSI_RESET);
    }

    // Mensaje de recuperacion de error
    public static void mensajeRecuperacion(String mensaje) {
        System.err.println(ANSI_CYAN + "[RECUPERACION] " + mensaje + ANSI_RESET);
    }

    // ===============================================================
    // 2.2 ANALISIS SEMANTICO
    // ===============================================================

    public static int erroresSemanticos = 0;

    // Reporta un error semantico
    public static void errorSemantico(String mensaje) {
        erroresSemanticos++;
        System.err.println(ANSI_RED + "[ERROR SEMANTICO] " + mensaje + ANSI_RESET);
    }

    // Busca un simbolo en toda la pila (de interno a externo)
    public static Simbolo buscarSimbolo(String nombre) {
        for (java.util.HashMap<String, Simbolo> ambito : pilaTablas) {
            if (ambito.containsKey(nombre)) return ambito.get(nombre);
        }
        return null;
    }

    // Verifica que una variable haya sido inicializada
    public static void marcarInicializada(String nombre) {
        Simbolo s = buscarSimbolo(nombre);
        if (s != null) s.inicializada = true;
    }

    // Verifica que una variable exista antes de usarla
    // Retorna: "tipo|nombre" o "error|?"
    public static String verificarUso(String nombre, int linea) {
        Simbolo s = buscarSimbolo(nombre);
        if (s == null) {
            errorSemantico("Linea " + linea + ": variable '" + nombre + "' no fue declarada.");
            return "error|?";
        }
        if (!s.inicializada) {
            errorSemantico("Linea " + linea + ": variable '" + nombre + "' se usa sin haber sido inicializada.");
        }
        return s.tipo + "|" + nombre;
    }

    // ===============================================================
    // 2.2.1 VALIDACION DE TIPOS
    // ===============================================================
    // Compara dos tipos y valida compatibilidad
    // Recibe: tipo1, tipo2, operacion, linea
    // Retorna: el tipo resultante o "error|?"
    
    public static String validarTipos(String tipo1, String tipo2, String operacion, int linea) {
        
        String t1 = tipo1;
        String t2 = tipo2;
        
        // Extraer solo el tipo si viene con temporal (formato "tipo|temp")
        if (tipo1 != null && tipo1.contains("|")) {
            t1 = tipo1.split("\\|")[0];
        }
        if (tipo2 != null && tipo2.contains("|")) {
            t2 = tipo2.split("\\|")[0];
        }
        
        // Si algun tipo es error, propagar error
        if (t1.equals("error") || t2.equals("error")) return "error|?";
        
        // Tipos incompatibles
        if (!t1.equals(t2)) {
            if (operacion.equals("asignacion")) {
                errorSemantico("Linea " + linea 
                    + ": tipo incompatible en asignacion, se esperaba '" + t1 
                    + "' pero se encontro '" + t2 + "'.");
            } else if (operacion.equals("return")) {
                errorSemantico("Linea " + linea 
                    + ": tipo de retorno incorrecto, se esperaba '" + t1 
                    + "' pero se encontro '" + t2 + "'.");
            } else {
                errorSemantico("Linea " + linea 
                    + ": tipos incompatibles en operacion '" + operacion 
                    + "', se encontraron '" + t1 + "' y '" + t2 + "'.");
            }
            return "error|?";
        }
        
        // Para operadores relacionales, retorna bool
        if (operacion.equals("less_t") || operacion.equals("less_te") || 
            operacion.equals("greather_t") || operacion.equals("greather_te") ||
            operacion.equals("equal") || operacion.equals("n_equal")) {
            return "bool|?";
        }
        
        // Para otros casos, retorna el mismo tipo
        return t1 + "|?";
    }

    // ===============================================================
    // 2.2.2 VALIDACIONES DE SWITCH
    // ===============================================================

    // Mapa: switchId -> tipo (int/char)
    private static java.util.HashMap<Integer, String> mapaTipoSwitch = new java.util.HashMap<>();
    
    // Mapa: switchId -> lugar (temporal de la expresion)
    private static java.util.HashMap<Integer, String> mapaLugarSwitch = new java.util.HashMap<>();

    // Mapa: switchId -> tiene_default (true/false)
    private static java.util.HashMap<Integer, Boolean> mapaDefaultSwitch = new java.util.HashMap<>();
    
    // Mapa: whileId -> etiqueta de inicio
    private static java.util.HashMap<Integer, String> mapaEtqInicioWhile = new java.util.HashMap<>();

    // Pilas para break anidados
    static java.util.Stack<String> pilaBreak = new java.util.Stack<>();

    static java.util.Stack<Integer> pilaContadorWhile = new java.util.Stack<>();

    static java.util.Stack<java.util.ArrayList<String>> pilaArgumentos = new java.util.Stack<>();

    // Guarda el tipo del switch
    private void setTipoSwitch(int switchId, String tipo) {
        mapaTipoSwitch.put(switchId, tipo);
    }
    
    // Obtiene el tipo del switch
    private String getTipoSwitch(int switchId) {
        return mapaTipoSwitch.getOrDefault(switchId, "desconocido");
    }
    
    // Mapa: switchId -> lista de constantes usadas en cases
    private static java.util.HashMap<Integer, java.util.ArrayList<String>> mapaConstantesSwitch = new java.util.HashMap<>();
    
    // Valida que no haya constantes duplicadas en el mismo switch
    private void agregarConstanteSwitch(int switchId, String constante, int linea) {
        if (!mapaConstantesSwitch.containsKey(switchId)) {
            mapaConstantesSwitch.put(switchId, new java.util.ArrayList<>());
        }
        java.util.ArrayList<String> constantes = mapaConstantesSwitch.get(switchId);
        if (constantes.contains(constante)) {
            errorSemantico("Linea " + linea + ": constante de case duplicada: " + constante);
        } else {
            constantes.add(constante);
        }
    }
    
    // Valida que solo haya un default por switch
    private void marcarDefaultUsado(int switchId, int linea) {
        if (mapaDefaultSwitch.getOrDefault(switchId, false)) {
            errorSemantico("Linea " + linea + ": solo puede haber un 'default' por switch");
        } else {
            mapaDefaultSwitch.put(switchId, true);
        }
    }

    // Guarda el lugar (temporal) de la expresion del switch
    private void setLugarSwitch(int id, String lugar) { 
        mapaLugarSwitch.put(id, lugar); 
    }
    
    // Obtiene el lugar de la expresion del switch
    private String getLugarSwitch(int id) { 
        return mapaLugarSwitch.getOrDefault(id, "?"); 
    }

    // Mapa: switchId -> casoId -> etiqueta de fin del case
    private static java.util.HashMap<Integer, java.util.HashMap<Integer, String>> mapaEtqCasos = new java.util.HashMap<>();

    // Guarda la etiqueta de fin de un case especifico
    private void setEtqCasoActual(int swId, int casoId, String etq) {
        mapaEtqCasos.computeIfAbsent(swId, k -> new java.util.HashMap<>()).put(casoId, etq);
    }
    
    // Obtiene la etiqueta de fin de un case
    private String getEtqCasoActual(int swId, int casoId) {
        return mapaEtqCasos.getOrDefault(swId, new java.util.HashMap<>())
                           .getOrDefault(casoId, "_sw" + swId + "_end");
    }

    // Guarda la etiqueta de inicio de un do-while
    private void setEtqInicioWhile(int id, String etq) {
        mapaEtqInicioWhile.put(id, etq);
    }

    // Obtiene la etiqueta de inicio de un do-while
    private String getEtqInicioWhile(int id) {
        return mapaEtqInicioWhile.getOrDefault(id, "_dowhile" + id + "_start");
    }

